import Loadable from "@loadable/component";
import ElasticFire from "codepen.io/elastic-fire";
import $ from "jquery";
import _ from "lodash";
// import path from "path";
import React from "react";
import ReactDOM from "react-dom";
import { SpinnerFlexButton as Loading } from "react-labs/src/components/Util";
import Lyon from "./assets/lyon.svg";
import LyonBig from "./assets/lyonBig.svg";
import "./style.css";

const FulDynamicImport = Loadable(props => import(`./${props.src}`));

const Fullscreen = Loadable(
  () => import("codepen.io/add-fullscreen-toggle-to-your-pen"),
  {
    fallback: <Loading />
  }
);
const GravityAnimatedPoster = Loadable(
  () => import("codepen.io/gravity-animated-poster"),
  {
    fallback: <Loading />
  }
);
const Gotothemoonpure = Loadable(
  () => import("codepen.io/gotothemoonpure-javascript"),
  {
    fallback: <Loading />
  }
);
const BackgroundGradient = Loadable(
  () => import("codepen.io/animated-background-gradient"),
  {
    fallback: <Loading />
  }
);
const VerticalMenu = Loadable(() => import("codepen.io/vertical-menu"), {
  fallback: <Loading />
});

export default class extends React.Component {
  constructor(props, context) {
    super(props, context);
    this.state = {
      background: null,
      isToggleOn: true
    };

    // Aqui utilizamos o `bind` para que o `this` funcione dentro da nossa callback
    this.handleClick = this.handleClick.bind(this);
    this.RunDynamicImport = this.RunDynamicImport.bind(this);
  }

  GetDynamicImport = () => {
    //  python -c 'import os, json; print json.dumps(os.listdir("."))'
    // replace \u2013 por -

    let obj;

    // console.log("path", path);
    // console.log(`path: `, Object.getOwnPropertyNames(path).sort());

    // Process pages through `yaml-frontmatter-loader` and `json-loader`.
    // The first one extracts the front matter and the body and the latter
    // converts it into a JSON structure to use later. Markdown
    // hasn't been processed yet.
    const req = require.context(
      "./assets/background",
      false, // Load files recursively. Pass false to skip recursion.
      /\.(png|jpe?g|svg)$/ // Match files ending with .md.
    );

    // console.log("req", req);

    let keys = req.keys();

    // console.log("keys: ", keys);

    obj = _.chain(keys)
      .map(function(value, index) {
        // console.log("value", value);
        var value = _.replace(value, "./", "");
        // console.log("value", value);
        return value;
      })
      .value();

    // console.log("obj", obj);
    // console.log("obj", typeof obj);

    // obj = [
    //   "Flag_of_Brazil.svg",
    // ];
    // console.log("obj", typeof obj);
    let length = obj.length - 1;
    // console.log("length", length);
    let random = _.random(0, length);
    let item = obj[random];
    // console.log("item", item);

    var p1 = FulDynamicImport.load({ src: "assets/background/" + item });
    // console.log(`p1: `, p1);
    p1.then(
      function(value) {
        // console.log("p1 value: ", value); // Success!
      },
      function(reason) {
        // console.log("p1 reason: ", reason); // Error!
      }
    );
    // console.log(`p1: `, p1);

    return p1;
  };

  RunDynamicImport = () => {
    var p2 = this.GetDynamicImport(this.props);
    // console.log(`p2: `, p2);
    var background;
    let current_this = this;
    p2.then(
      function(value) {
        // console.log("p2 value: ", value); // Success!
        background = value.default;
        // console.log("p2.then", current_this);
        current_this.setState({ background: background });
        // console.log(`current_this.state: `, current_this.state);
      },
      function(reason) {
        // console.log("p2 reason: ", reason); // Error!
      }
    );

    // console.log(`p2: `, p2);

    return p2;
  };

  handleClick(e) {
    // console.log("handleClick: ", e);
    // console.log("this is:", this);

    // e.preventDefault();
    //
    this.setState(state => ({
      isToggleOn: !state.isToggleOn
    }));
    //
    $(".js-next").addClass("is-active");
    //
    const App = Loadable(() => import("react-labs/src/App"), {
      fallback: <Loading />
    });
    ReactDOM.render(<App />, document.getElementById("root"));
    //
  }

  componentDidMount() {
    // console.log("componentDidMount", this);
    //
    require("./script.js");

    //

    var p3 = this.RunDynamicImport(this.props);
    // console.log(`p3: `, p3);

    //
  }

  render() {
    // console.log("render", this);
    if (typeof this.state.background === "undefined") {
      return <span>Carregando: {this.state.background}</span>;
    }
    return (
      <>
        <div id="app">
          <header></header>
          <main id="main-pl">
            <div className="layers">
              <div className="layer">
                <BackgroundGradient />
              </div>
              <div className="layer">
                <Gotothemoonpure />
              </div>
              <div className="layer">
                <GravityAnimatedPoster />
              </div>
              <div className="layer">
                <ElasticFire />
              </div>

              <div className="layer">
                <div className="parent-pl 0scale-up-center">
                  <div className="pl">
                    <i
                      className="pl__bg js-bg"
                      style={{
                        backgroundImage: `url(${this.state.background})`
                      }}
                    ></i>
                    <i className="pl__logo-inverted js-logo-inverted">
                      <img src={Lyon} />
                    </i>

                    <div className="pl__heading js-heading">
                      <div className="logo__parent">
                        <i className="logo__left js-logo-left">
                          <span>Mozg</span>
                        </i>
                        <i className="logo__center js-logo">
                          <span className="lion">
                            <img src={LyonBig} />
                          </span>
                          <span className="text-container js-text-container">
                            <p className="text-container__placeholder">
                              O futuro chegou
                            </p>
                          </span>
                          <span className="text js-text">O futuro chegou</span>
                        </i>
                        <i className="logo__right js-logo-right">
                          <span>Brasil</span>
                        </i>
                      </div>
                    </div>
                  </div>

                  <button
                    className="pl__button js-next"
                    onClick={() => this.handleClick()}
                  >
                    {this.state.isToggleOn ? "Prosseguir" : "Prosseguindo"}
                  </button>
                  <div className="pl__button js-restart">Restart</div>
                </div>
              </div>

              {/* <div className="layer">
            <Gotothemoonpure />
          </div> */}
            </div>
          </main>
          <footer></footer>

          <Fullscreen />
          <VerticalMenu />
        </div>
      </>
    );
  }
}
